INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-3218f787-moex-00186', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '語言作為一個重要的文化元素。社會學家有關語言的解釋，並不包括下列那個內容？', '["語言是一組符號與規則系統，賦予了人們理解與溝通所需要的意義", "語言定義了社會真實（socialreality）的基本範疇", "語言中可能隱藏著社會不平等", "語言是一個靜態，且不隨時間變動的結構系統"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00187', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '在古典社會學理論的發展中，認為社會屬自成一體的實體，而這個實體又是一個存在個體之外的 社會事實（socialfact）。這是下列那位社會學家的主要論點？', '["馬克思（KarlMarx）", "涂爾幹（EmileDurkheim）", "韋伯（MaxWeber）", "奧古斯特．孔德（AugusteComte）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00188', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '社會學家米爾斯（C.WrightMillis）曾強調社會學可增進人們的「社會學的想像」（sociological imagination）。下列何者不是米爾斯所主張之社會學想像的內容？', '["社會學關心個人的各種議題", "社會學嘗試了解個人與所處社會的關係", "社會學會揭露社會脈絡", "個人問題與社會問題必須加以區隔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00189', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於「集體行為」特性的描述，何者正確？', '["每天一起通勤坐公車上班的行為，可算得上是一種集體行為", "傳播流言乃是一種集體行為，通常發生在沒有足夠資訊可以解釋問題情境或事件時", "集體行為乃是個人非理性、激情行為的集合", "集體行為都是長時間模塑形成，並非一時的流行或時尚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00190', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於「族群關係」相關議題的說明與解釋，何者錯誤？', '["肯認行動（affirmativeaction）是指政府為保障弱勢族群在工作或教育等之機會的制度性保障機制", "認可性政治（politicsofrecognition）主要是在處理與個人或群體認同有關的記憶、歷史，以及用以 界定「我們是誰」的基本特質的政治行動", "轉型正義（transitionaljustice）是一個社會在民主轉型之後，對過去威權體制的政治壓迫，以及因 其所產生的社會分裂所做的善後工作", "重分配政治（politicsofredistribution）是在說明，如何分配社會中豐富的政治及經濟資源，包括收 入、機會及政治職位等政治性的活動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00191', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列社會學對「貧窮」的說明與看法，何者正確？', '["所謂貧窮女性化，指的是女性與老人占貧窮人口高比例的事實", "造成貧窮的主要原因，乃是個人缺乏責任心及工作動機所造成，這是貧窮文化論主要的觀點", "貧窮線，乃是政府所訂定，為維持一個個人基本生活所需金額的一種判斷標準", "貧窮主要是經濟不景氣所造成，而與犯罪問題、族群、學歷、健康照顧制度等因素沒有關聯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00192', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於社會學解釋「犯罪行為」相關理論的說明，何者錯誤？', '["從結構功能論來看，犯罪行為可以釐清社會規範的價值，犯罪行為的存在是對社會具有一定的 功能", "從衝突論的觀點，其認為犯罪是區域不平衡發展過程中，民眾利益衝突下的產物，以芝加哥學 派的理論為代表", "從結構功能論的觀點，犯罪行為主要是源自於社會中的結構緊張而產生", "從符號互動論的觀點，犯罪是人們經歷社會互動而習得的行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00193', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '關於「社會化」的相關概念，下列陳述何者錯誤？', '["社會化主要發生在兒童及青少年階段，以其來學習社會規範", "社會化是個體將社會期待內化（internalization）的一種學習過程", "斯德哥爾摩症候群（StockholmSyndrome），主要是解釋在嚴苛監禁下，被監禁者產生認同監 禁者行為的極端再社會化現象", "社會化可做為社會控制的一種方式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00194', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '下列關於古典社會學家所提出之相關理論或觀念的陳述，何者正確？', '["馬克思（KarlMarx）的許多論述主要都是針對社會主義的生產制度提出嚴厲的批判", "涂爾幹（EmileDurkheim）所提出的社會分工論，主要是在說明現代社會秩序的維持，是從過 去人與人之間有機連結（organic solidarity）為基礎的社會，轉換成以機械連結（mechanical solidarity）為基礎的社會", "韋伯（MaxWeber）的社會學可稱之為「詮釋社會學」，因為他認為在社會中人的行動是具有 主觀意識，因此必須從「行動者」的角度來理解其意義", "馬克思（KarlMarx）所提出的迷亂理論（anomietheory），主要在說明現代社會中工人所從事 的生產工作與其生活產生脫節，而失去對生活控制的現象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "31bace84baa1", "answer_pdf_sha1": "d8c1488dee32", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00195', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-90de4de6', 'sub-generalpolice-3218f787-06', NULL, 'essay', '研究倫理是一位研究者必須恪遵的基本信念，為落實研究倫理，研究過程
